import React, { useEffect } from 'react';
import useStore from '../store/useStore';
import { initSocket } from '../utils/socket';
import { useSocket } from '../hooks/useSocket';
import Sidebar from '../components/layout/Sidebar';
import ChannelHeader from '../components/layout/ChannelHeader';
import ChatArea from '../components/chat/ChatArea';
import ThreadPanel from '../components/chat/ThreadPanel';
import TasksPanel from '../components/tasks/TasksPanel';
import DecisionsPanel from '../components/decisions/DecisionsPanel';
import MembersPanel from '../components/layout/MembersPanel';

export default function WorkspacePage() {
  const { token, user, setUser, fetchChannels, fetchTasks, fetchDecisions, fetchUsers, rightPanel, activeThread } = useStore();

  useSocket();

  useEffect(() => {
    if (!token) return;
    // Boot socket
    const s = initSocket(token);

    // Load initial data
    fetchChannels();
    fetchTasks();
    fetchDecisions();
    fetchUsers();

    // Fetch current user if needed
    if (!user) {
      import('../utils/api').then(({ default: api }) => {
        api.get('/auth/me').then(r => setUser(r.data.user)).catch(() => {});
      });
    }

    return () => s.disconnect();
  }, [token]);

  return (
    <div style={styles.workspace}>
      <Sidebar />

      <div style={styles.main}>
        <ChannelHeader />
        <div style={styles.content}>
          <ChatArea />
          {activeThread && <ThreadPanel />}
        </div>
      </div>

      {rightPanel === 'tasks'     && <TasksPanel />}
      {rightPanel === 'decisions' && <DecisionsPanel />}
      {rightPanel === 'members'   && <MembersPanel />}
    </div>
  );
}

const styles = {
  workspace: { display: 'flex', height: '100vh', overflow: 'hidden', background: 'var(--bg-void)' },
  main: { flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden', minWidth: 0 },
  content: { flex: 1, display: 'flex', overflow: 'hidden' }
};
